const rawData = $input.all();

// Mengambil parameter filter dari node AI laporan Anda
const filterData = $('Code in JavaScript4').first().json; 

let grandTotalIncome = 0;
let grandTotalExpense = 0;

// Objek penampung data yang dikelompokkan
const groupedData = {};

// 1. PROSES PENYARINGAN & AKUMULASI DATA
rawData.forEach(item => {
  const row = item.json;
  const method = row.payment_method || "Lainnya";

  // Filter berdasarkan jenis dan metode pembayaran
  if (filterData.target_type !== "ALL" && row.transaction_type !== filterData.target_type) return;
  if (filterData.target_method !== "ALL" && method.toLowerCase() !== filterData.target_method.toLowerCase()) return;

  // Inisialisasi struktur grup jika belum ada
  if (!groupedData[method]) {
    groupedData[method] = {
      income: 0,
      expense: 0,
      items: []
    };
  }

  // Akumulasi nominal ringkasan utama & per dompet digital
  if (row.transaction_type === "INCOME") {
    grandTotalIncome += row.amount;
    groupedData[method].income += row.amount;
  }
  if (row.transaction_type === "EXPENSE") {
    grandTotalExpense += row.amount;
    groupedData[method].expense += row.amount;
  }

  // Simpan rincian baris transaksi (menggunakan deskripsi, tanpa kategori)
  const icon = row.transaction_type === "INCOME" ? "🟢" : "🔴";
  const desc = row.description ? row.description : "Tanpa catatan";
  groupedData[method].items.push(`${icon} ${row.transaction_date} | Rp${row.amount.toLocaleString('id-ID')} - ${desc}`);
});

// ==========================================
// 2. MERANGKAI TEKS OUTPUT AKHIR UNTUK WHATSAPP
// ==========================================

let reportText = `📊 *LAPORAN KEUANGAN*\n🗓️ ${filterData.start_date} s/d ${filterData.end_date}\n\n`;

if (Object.keys(groupedData).length === 0) {
  reportText += "Tidak ada transaksi yang sesuai dengan kriteria pencarian ini.";
} else {
  // Tampilkan Grand Total Seluruh Aliran Dana
  if (filterData.target_type === "ALL" || filterData.target_type === "INCOME") {
    reportText += `📥 *Total Pemasukan:* Rp${grandTotalIncome.toLocaleString('id-ID')}\n`;
  }
  if (filterData.target_type === "ALL" || filterData.target_type === "EXPENSE") {
    reportText += `📤 *Total Pengeluaran:* Rp${grandTotalExpense.toLocaleString('id-ID')}\n`;
  }

  reportText += `\n➖➖➖➖➖➖➖➖➖➖\n`;

  // Tampilkan Per Dompet Digital secara Terpisah beserta Sisa Saldonya
  for (const method in groupedData) {
    const income = groupedData[method].income;
    const expense = groupedData[method].expense;

    // MATEMATIKA SALDO: Pemasukan dikurangi Pengeluaran pada periode tersebut
    const sisaSaldoPeriode = income - expense; 

    reportText += `\n💳 *${method.toUpperCase()}*\n`;
    reportText += `💰 *Sisa Saldo Periode:* Rp${sisaSaldoPeriode.toLocaleString('id-ID')}\n`;
    // PERBAIKAN TYPO ADA DI BARIS BAWAH INI
    reportText += `📈 _(In: Rp${income.toLocaleString('id-ID')} | Out: Rp${expense.toLocaleString('id-ID')})_\n`;
    reportText += `📋 *Rincian Acara:* \n`;

    // Tampilkan list transaksi di bawah dompet ini
    groupedData[method].items.forEach(line => {
      reportText += `${line}\n`;
    });
  }
}

return [{ json: { final_report: reportText } }];

