// 1. Ambil data keputusan dari Matchmaker AI
const matchmaker = $input.first().json;

// 2. Tarik daftar seluruh agenda mentah dari node Google Calendar sebelumnya
const semuaAgenda = $('Get many events1').all();

// 3. Cari objek agenda asli yang cocok dengan event_id dari Matchmaker
const agendaAsli = semuaAgenda.find(item => item.json.id === matchmaker.event_id)?.json;

if (!agendaAsli) {
  throw new Error("Gagal menyinkronkan data waktu: Agenda asli tidak ditemukan di array.");
}

// 4. Ambil data instruksi waktu dari AI pertama (Parser JSON)
const dataAI1 = $('Parser JSON7').first().json;

let finalStart = agendaAsli.start.dateTime || agendaAsli.start.date;
let finalEnd = agendaAsli.end.dateTime || agendaAsli.end.date;

// FUNGSI BANTUAN: Memaksa penambahan Zona Waktu jika AI lupa
function formatTz(dStr) {
  if (!dStr) return "";
  if (dStr.length === 10) return dStr + "T00:00:00+07:00"; // Jika AI hanya membalas "YYYY-MM-DD"
  if (!dStr.includes("+") && !dStr.endsWith("Z")) {
    return dStr + "+07:00"; // Jika AI lupa timezone (Ini yang mencegah bug jam 13:00)
  }
  return dStr;
}

// 5. KONDISI JIKA USER MELAKUKAN RESCHEDULE (UBAH WAKTU)
if (dataAI1.start_datetime && dataAI1.start_datetime !== "") {
  const oldStartDateStr = agendaAsli.start.dateTime || agendaAsli.start.date;

  // Lewatkan string waktu ke fungsi pengaman kita
  let newStartDateStr = formatTz(dataAI1.start_datetime);
  let newEndDateStr = formatTz(dataAI1.end_datetime);

  let stringWaktuMulai = newStartDateStr;

  // Cek jika user tidak memberikan jam (Ditandai dengan AI memberikan T00:00:00)
  if (newStartDateStr.includes("T00:00:00") && oldStartDateStr.includes("T")) {
    const tanggalBaru = newStartDateStr.split("T")[0]; 
    const jamLama = oldStartDateStr.split("T")[1];     
    stringWaktuMulai = `${tanggalBaru}T${jamLama}`;    
  }

  const waktuMulaiBaru = new Date(stringWaktuMulai).getTime();
  let waktuSelesaiBaru;

  // Cek apakah AI memberikan end_datetime spesifik yang BUKAN jam 00:00
  if (newEndDateStr && newEndDateStr !== "" && !newEndDateStr.includes("T00:00:00")) {
    waktuSelesaiBaru = new Date(newEndDateStr).getTime();
  } else {
    // Gunakan durasi asli jadwal jika tidak ada instruksi jam selesai baru
    const waktuMulaiAsli = new Date(oldStartDateStr).getTime();
    const waktuSelesaiAsli = new Date(finalEnd).getTime();
    const durasiMilidetik = waktuSelesaiAsli - waktuMulaiAsli;

    waktuSelesaiBaru = waktuMulaiBaru + durasiMilidetik;
  }

  function toISOJakarta(ms) {
    return new Date(ms + 25200000).toISOString().replace('.000Z', '+07:00');
  }

  finalStart = toISOJakarta(waktuMulaiBaru);
  finalEnd = toISOJakarta(waktuSelesaiBaru);
}

// 6. GABUNGKAN DATA UNTUK PAYLOAD UPDATE
return [{
  json: {
    event_id: matchmaker.event_id,
    summary: matchmaker.new_title && matchmaker.new_title !== "" ? matchmaker.new_title : agendaAsli.summary,
    new_start: finalStart,
    new_end: finalEnd,
    location: matchmaker.new_location && matchmaker.new_location !== "" ? matchmaker.new_location : (agendaAsli.location || ""),
    description: matchmaker.new_description && matchmaker.new_description !== "" ? matchmaker.new_description : (agendaAsli.description || "")
  }
}];

