// 1. Ambil data dari node Update Google Calendar sebelumnya
const event = $input.first().json;

// 2. Ekstrak waktu mentah
const startTimeStr = event.start?.dateTime || event.start?.date || "";
const endTimeStr = event.end?.dateTime || event.end?.date || "";

// 3. Fungsi cerdas untuk menggabungkan waktu agar tidak kaku
function formatWaktu(start, end) {
  if (!start) return "-";

  const tglOptions = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric', timeZone: 'Asia/Jakarta' };
  const jamOptions = { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Jakarta' };

  // Jika all-day event (hanya tanggal YYYY-MM-DD tanpa jam)
  if (start.length === 10) {
    const dStart = new Date(start);
    const tglStartStr = dStart.toLocaleDateString('id-ID', tglOptions);
    return `${tglStartStr} (Seharian)`;
  }

  // Jika acara memiliki jam spesifik
  const dStart = new Date(start);
  const dEnd = end ? new Date(end) : dStart;

  const tglStartStr = dStart.toLocaleDateString('id-ID', tglOptions);
  const tglEndStr = dEnd.toLocaleDateString('id-ID', tglOptions);

  const jamStartStr = dStart.toLocaleTimeString('id-ID', jamOptions).replace(/\./g, ':');
  const jamEndStr = dEnd.toLocaleTimeString('id-ID', jamOptions).replace(/\./g, ':');

  // LOGIKA PENGGABUNGAN:
  // Jika harinya sama, gabungkan jamnya saja (Contoh: Kamis, 25 Juni 2026, 05:00 - 08:00 WIB)
  if (tglStartStr === tglEndStr) {
    return `${tglStartStr}, ${jamStartStr} - ${jamEndStr} WIB`;
  } else {
  // Jika harinya beda, tampilkan keduanya
    return `${tglStartStr} ${jamStartStr} WIB - ${tglEndStr} ${jamEndStr} WIB`;
  }
}

// 4. Ekstrak data yang dibutuhkan
const summary = event.summary || "Agenda Tanpa Judul";
const waktuGabungan = formatWaktu(startTimeStr, endTimeStr);
const location = event.location || "-";
const description = event.description || "-";

// 5. Return data bersih untuk AI
return [{
  json: {
    judul_agenda: summary,
    waktu_pelaksanaan: waktuGabungan,
    lokasi: location,
    catatan: description
  }
}];

